    {
      "id": "D1",
      "content": "プロジェクト・アオゾラを本日をもって正式発足とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D2",
      "content": "週次定例を毎週水曜日の10時からの1時間枠で開催する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D3",
      "content": "開発ベンダーはコマツバ・ソリューションズとする。",
      "decided_by": "郡司 明久"
    },
    {
      "id": "D4",
      "content": "認証とマスタ配信の基盤は、サクラ商事との共同利用（第3案）で行う。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D5",
      "content": "データ移行は第1フェーズでマスタ系のみを移行し、トランザクション系は旧システムを参照用に残す。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D6",
      "content": "移行方式は拠点を分けて段階的に切り替える方法（B案）を採用する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D7",
      "content": "本番リリースの目標日付を9月末から10月15日に変更する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D8",
      "content": "システムの切り替え作業は土曜日の深夜帯に行う。",
      "decided_by": "沼田 賢一"
    },
    {
      "id": "D9",
      "content": "新システムでのユーザー権限設計は既存のロール定義を流用し、新規設計は行わない。",
      "decided_by": "芦田 巧"
    },
    {
      "id": "D10",
      "content": "障害発生時の一次受け窓口を情報システム部からQAチームに変更する。",
      "decided_by": "白鳥 千夏"
    }
  ],
